#!/usr/bin/env python3
import subprocess
import sys
from collections import deque

class MazeExplorer:
    def __init__(self):
        self.visited = set()
        self.walls = set()
        self.open_spaces = set()
        self.current_pos = (0, 0)  # Starting position
        self.start_pos = (0, 0)
        self.exit_pos = None
        self.process = None

    def start_game(self):
        self.process = subprocess.Popen(
            ['/app/maze_game.sh'],
            stdin=subprocess.PIPE,
            stdout=subprocess.PIPE,
            stderr=subprocess.PIPE,
            text=True,
            bufsize=1
        )
        # Read initial welcome message
        while True:
            line = self.process.stdout.readline()
            if '>' in line:
                break

    def send_command(self, command):
        self.process.stdin.write(command + '\n')
        self.process.stdin.flush()
        response = ''
        while True:
            line = self.process.stdout.readline()
            if '>' in line:
                break
            response += line
        return response.strip()

    def move(self, direction):
        directions = {'N': (0, 1), 'S': (0, -1), 'E': (1, 0), 'W': (-1, 0)}
        dx, dy = directions[direction]
        new_pos = (self.current_pos[0] + dx, self.current_pos[1] + dy)

        response = self.send_command(f'move {direction}')

        if 'hit wall' in response:
            self.walls.add(new_pos)
            return False
        elif 'moved' in response:
            self.current_pos = new_pos
            self.open_spaces.add(new_pos)
            return True
        elif 'reached exit' in response:
            self.current_pos = new_pos
            self.open_spaces.add(new_pos)
            self.exit_pos = new_pos
            return True
        return False

    def explore_systematically(self):
        self.open_spaces.add(self.current_pos)
        stack = [(self.current_pos, [])]  # (position, path_to_get_here)
        explored_positions = set()

        while stack:
            target_pos, path = stack.pop()

            if target_pos in explored_positions:
                continue

            # Navigate to target position
            if path:
                batch_command = ' & '.join(path)
                response = self.send_command(f'move {batch_command}')
                responses = response.split(' & ')

                # Update current position based on successful moves
                for i, (direction, resp) in enumerate(zip(path, responses)):
                    if 'moved' in resp or 'reached exit' in resp:
                        directions = {'N': (0, 1), 'S': (0, -1), 'E': (1, 0), 'W': (-1, 0)}
                        dx, dy = directions[direction]
                        self.current_pos = (self.current_pos[0] + dx, self.current_pos[1] + dy)
                        if 'reached exit' in resp:
                            self.exit_pos = self.current_pos
                    else:
                        break

            explored_positions.add(self.current_pos)

            # Test all four directions
            for direction in ['N', 'S', 'E', 'W']:
                directions = {'N': (0, 1), 'S': (0, -1), 'E': (1, 0), 'W': (-1, 0)}
                dx, dy = directions[direction]
                new_pos = (self.current_pos[0] + dx, self.current_pos[1] + dy)

                response = self.send_command(f'move {direction}')

                if 'hit wall' in response:
                    self.walls.add(new_pos)
                elif 'moved' in response or 'reached exit' in response:
                    self.open_spaces.add(new_pos)
                    if 'reached exit' in response:
                        self.exit_pos = new_pos

                    if new_pos not in explored_positions:
                        # Add to stack with path to get there
                        new_path = [direction]
                        stack.append((new_pos, new_path))

                    # Move back
                    reverse = {'N': 'S', 'S': 'N', 'E': 'W', 'W': 'E'}
                    self.send_command(f'move {reverse[direction]}')

    def create_map(self):
        if not self.open_spaces:
            return

        # Find bounds
        min_x = min(pos[0] for pos in self.open_spaces | self.walls)
        max_x = max(pos[0] for pos in self.open_spaces | self.walls)
        min_y = min(pos[1] for pos in self.open_spaces | self.walls)
        max_y = max(pos[1] for pos in self.open_spaces | self.walls)

        # Create map
        map_lines = []
        for y in range(max_y, min_y - 1, -1):
            line = ''
            for x in range(min_x, max_x + 1):
                pos = (x, y)
                if pos == self.start_pos:
                    line += 'S'
                elif pos == self.exit_pos:
                    line += 'E'
                elif pos in self.open_spaces:
                    line += ' '
                elif pos in self.walls:
                    line += '#'
                else:
                    line += '#'  # Unknown areas are walls
            map_lines.append(line)

        with open('/app/maze_map.txt', 'w') as f:
            for line in map_lines:
                f.write(line + '\n')

    def close_game(self):
        self.send_command('exit')
        self.process.terminate()

if __name__ == '__main__':
    explorer = MazeExplorer()
    explorer.start_game()
    explorer.explore_systematically()
    explorer.close_game()
    explorer.create_map()
    print("Maze exploration complete. Map saved to /app/maze_map.txt")
